#include <stdio.h>

int main() {
    long long T, B, S, W, L;
    scanf("%lld", &T);
    scanf("%lld", &B);
    scanf("%lld", &S);
    scanf("%lld", &W);
    scanf("%lld", &L);

    long long branches = T * B;
    long long smallBranches = branches * S;
    long long twigs = smallBranches * W;
    long long leaves = twigs * L;

    printf("%lld\n", branches);
    printf("%lld\n", smallBranches);
    printf("%lld\n", twigs);
    printf("%lld\n", leaves);

    return 0;
}
